import React from 'react';
import auth from '../services/auth';

const Topbar = ()=>{
  const profile = auth.getProfile();
  return (
    <div className="topbar">
      <div>
        <h2 style={{margin:0}}>Admin Panel</h2>
        <div className="small-muted">Welcome back, {profile?.email||'Administrator'}</div>
      </div>
      <div style={{display:'flex',gap:12,alignItems:'center'}}>
        <div className="hint">Authorized Administrators Only</div>
        <button className="btn secondary" onClick={()=>{auth.logout();window.location.href='/login';}}>Logout</button>
      </div>
    </div>
  );
}

export default Topbar;
